        ARRRG_WELCOME_T_NORG_I_M_GILGAMESH_THE                               = 10107,  -- Arrrg, welcome t'Norg. I'm Gilgamesh, the leader of these scallywags. Me daughter's filled me in on your tale.
        I_VE_HAD_ME_SUSPICIONS_ABOUT_JEUNO_FER                               = 10108,  -- I've had me suspicions about Jeuno fer years. That's why I had Lion investigatin' these past months.
