        I_LL_HELP_YOU_LOOK_FOR_HER_ALDO                                      = 10135,  -- I'll help you look for her, Aldo. If anything happened to Verena...
        NO_LION_I_HAVE_ANOTHER_JOB_FER_YOU                                   = 10136,  -- No, Lion. I have another job fer you.
