        ID_1QHB_6_A_J_V5_JD_5JQ_8                                            = 10141,  -- 1qHb%6?a-j\"%v5\jD%?\$)`5jq% &8%>/E2Wiq>B
        CI_IA_IBAD_G_1F_IB                                                   = 10142,  -- CI%&Ia%<IbAD`g"="1F* iB
        ARRRG_I_HEARD_FROM_LION_ABOUT_WHAT_HAPPENED                          = 10143,  -- Arrrg, I heard from Lion about what happened at Delkfutt's Tower.
        OUR_ANCIENT_FRIEND_CALLED_THAT_ISLAND_FLOATIN_OVER                   = 10144,  -- Our ancient friend called that island floatin' over Qufim Tu'Lia...the Gate of the Gods.
        EALD_NARCHE_ALSO_SAID_THAT_ONLY_THOSE_WHO                            = 10145,  -- Eald'narche also said that only those who have been blessed by the light and whose power has been accepted by the crystal can pass through the gate.
        WHAT_DOES_THAT_BOY_THINK_HE_S_DOING                                  = 10146,  -- What does that boy think he's doing, playing some kind of game with Vana'diel as his prize?
        KAMUI_HAVE_YOU_EVER_HEARD_THE_NAME_RO                                = 10147,  -- Kamui. Have you ever heard the name Ro'Maeve? Eald'narche mentioned it before he left Delkfutt's Tower.
        RO_MAEVE_HMMM                                                        = 10148,  -- Ro'Maeve? Hmmm...
        ON_THE_NORTHERN_TIP_OF_MINDARTIA_IS_A                                = 10149,  -- On the northern tip of Mindartia is a wild, untamed region called the Sanctuary of Zi'Tah. In this area there remains a set of ancient ruins.
        I_REMEMBER_THOSE_RUINS_BEING_REFERRED_TO_AS                          = 10150,  -- I remember those ruins being referred to as Ro'Maeve.
        HOWEVER_THOSE_RUINS_ALSO_KNOWN_AS_THE_TEMPLE                         = 10151,  -- However, those ruins, also known as the Temple of Desolation, have long been feared by many.
        ARRRG_A_FRIGHTENIN_PLACE_THAT_ZI_TAH_BE                              = 10152,  -- Arrrg, a frightenin' place that Zi'Tah be. Ya never know what's gonna creep up behind yer back.
        TAKE_CARE_WHEN_TRAVELING_UP_THERE_UNLESS_YA                          = 10153,  -- %, take care when traveling up there, unless ya want to be swimmin' in Davy Jones's locker.
        OKAY_I_LL_BE_CAREFUL                                                 = 10154,  -- Okay, I'll be careful.
        HOLD_ON_THERE_MISSY_YOU_RE_NOT_GOING                                 = 10155,  -- Hold on there, missy. You're not going with % this time. I need ya t'travel t'Jeuno and keep an eye on them beastmen.
        BUT_BUT                                                              = 10156,  -- But...but!
        DON_T_TALK_BACK_T_ME_YOU_KNOW                                        = 10157,  -- Don't talk back t'me. You know what ya have t'do, now go do it! I'll stay here and watch after me hideout.
        ID_10158                                                             = 10158,  -- ...
        GNYAH_HAH_HOH_A_FINE_LOOKIN_ADVENTURER_YOU                           = 10159,  -- Gnyah-hah-hoh! A fine lookin' adventurer you are. I heard that if the price is right, your kind will do almost anything.
        HOW_S_ABOUT_IT_ARE_YA_GAME                                           = 10160,  -- How's about it? Are ya game?
        ACCEPT_MUZAFFAR_S_OFFER_YES_NO                                       = 10161,  -- Accept Muzaffar's offer? Yes. No.
        THAT_S_TOO_BAD_I_WAS_READY_TO                                        = 10162,  -- That's too bad. I was ready to pay a bundle... Guess I'll just have to find someone with a little more moxie.
        THAT_S_THE_ANSWER_I_WAS_LOOKIN_FOR                                   = 10163,  -- That's the answer I was lookin' for! As you know, we sell items here that are forbidden to import and export on the mainland.
        BUT_AS_OF_LATE_THERE_S_BEEN_MIGHTY                                   = 10164,  -- But as of late there's been mighty more demand than our supply can handle. We just don't have enough people to keep up. That's where you come in.
        IF_YOU_CAN_MAKE_IT_HERE_YOU_CAN                                      = 10165,  -- If you can make it here, you can make it to where all those forbidden items are found. You bring me some, and I'll pay you well. Oh, and I wouldn't try sellin' the goods at any other shop. You won't get ten gil for them.
