        BRING_THEM_TO_ME_IN_SETS_FOUR_ITEMS                                  = 10167,  -- Bring them to me in sets. Four items make one set. I'll pay you for one set at a time.
        YOU_ALREADY_FORGOT_WHAT_I_WANT_YOU_TO                                = 10168,  -- You already forgot what I want you to bring? Not that smart for an adventurer, are you? Now listen up, I don't want to have to tell you again.
        GNYAH_HOH_HOH_IF_IT_ISN_T_A                                          = 10169,  -- Gnyah-hoh-hoh! If it isn't a set of %! Here's the payment I promised you.
        IF_YOU_EVER_COME_ACROSS_ANY_MORE_BRING                               = 10170,  -- If you ever come across any more, bring them to me, 'cause I'll be happy to take them off your hands for you. Like they say, You scratch my back, I'll scratch yours.
