        A_KATANA_IS_A_WORK_OF_ART_I                                          = 10190,  -- A katana is a work of art. I refuse to replace the traditional methods of smithing with modern synthesis. However, my supply of materials is currently running low.
        IF_THESE_ITEMS_WERE_EASY_TO_COME_BY                                  = 10191,  -- If these items were easy to come by, I would go myself. Unfortunately, this is not the case, and I require your assistance.
        LISTEN_TO_JAUCRIBAIX_S_REQUEST_YES_NO                                = 10192,  -- Listen to Jaucribaix's request? Yes. No.
        I_SEE_I_APOLOGIZE_FOR_TAKING_UP_YOUR                                 = 10193,  -- I see. I apologize for taking up your valuable time.
        AH_HAVE_YOU_RECONSIDERED_MY_OFFER                                    = 10194,  -- Ah, have you reconsidered my offer?
        I_AM_GRATEFUL_FOR_YOUR_ASSISTANCE_WOULD_YOU                          = 10195,  -- I am grateful for your assistance. Would you be so kind as to fetch me % and %?
        THE_IS_FOR_THE_FLAME_THAT_FUELS_MY                                   = 10196,  -- The % is for the flame that fuels my furnace, and the % is the perfect material for melting the iron. Both are needed to forge a true katana blade.
        TO_LEARN_OF_WHERE_YOU_MAY_COME_ACROSS                                = 10197,  -- To learn of where you may come across these items, ask my pupils.
