        WONDERFUL_THESE_ARE_THE_MATERIALS_THAT_I_REQUIRE                     = 10202,  -- Wonderful. These are the materials that I require. I apologize, but I must hurry or Gilgamesh will have my head. I will reward you for your services when I have finished the katana.
        HOW_LONG_WILL_IT_TAKE_YOU_ASK_A                                      = 10203,  -- How long will it take, you ask? A good blade takes at least three full days to complete. Come to me then. You need not worry. I will be right here.
        AGAIN_I_APOLOGIZE_FOR_NOT_BEING_ABLE_TO                              = 10204,  -- Again, I apologize for not being able to give you your reward sooner.
        MY_WORK_IS_NOT_YET_COMPLETE_I_STILL                                  = 10205,  -- My work is not yet complete. I still require # [more hour/more hours]. It is not wise to waste your time trying to outrun the clock in this game we call life.
        TIME_IS_LIKE_A_FLOWING_RIVER_IT_CANNOT                               = 10206,  -- Time is like a flowing river--it cannot be sped up or slowed down. We must float along at the pace it has chosen.
        AH_YOU_HAVE_FINALLY_RETURNED_I_WAS_BEGINNING                         = 10207,  -- Ah, %, you have finally returned. I was beginning to worry that you had forgotten about your reward.
        NOW_WHERE_DID_I_PUT_THAT                                             = 10208,  -- Now where did I put that...
