        GILGAMESH                                                            = 10210,  -- Gilgamesh.
        YA_DID_SOME_MIGHTY_FINE_WORK_IN_GETTIN                               = 10211,  -- Ya did some mighty fine work in gettin' me matey, Jauc, his materials. Thanks t'you, I got meself a fine new blade.
        LISTEN_CAREFULLY_WITHIN_A_KATANA_THE_SOUL_OF                         = 10212,  -- Listen carefully, %. Within a katana, the soul of its maker and the soul of its wielder are intertwined.
