        YOU_ACCEPT_THE_FROM_GILGAMESH_YOU_CAN_NOW                            = 10219,  -- You accept the % from Gilgamesh. You can now become a samurai.
        I_WISH_TO_GIVE_YOU_YOUR_REWARD_BUT                                   = 10220,  -- I wish to give you your reward, but you seem to be carrying too much already. Come back when you have more room in your pack.
        CRYSTAL_TECHNOLOGY_HAS_HELPED_VANA_DIEL_PROSPER_BUT                  = 10221,  -- Crystal technology has helped Vana'diel prosper, but at the cost of traditional methods, now lost forever.
        JUST_AS_THE_OLD_IS_REPLACED_BY_THE                                   = 10222,  -- Just as the old is replaced by the new, the world is constantly changing. One day, one may no longer be able to live by a single blade alone.
        SO_YOU_NEED_I_SEE_MASTER_JAUCRIBAIX_IS                               = 10223,  -- So, you need %. I see Master Jaucribaix is starting another project. Let me tell you where to find that item.
