        DO_YOU_SEE_WHAT_I_HAVE_TO_DEAL                                       = 10524,  -- Do you see what I have to deal with? I don't know how much longer I can work with such a pessimist.
        THAT_S_WHERE_YOU_COME_IN_I_WAS                                       = 10525,  -- That's where you come in. I was thinking of letting one of you adventurers test out the new fork and prove to my colleague that it is able to return data valuable to his research.
        NO_NO_NO_NO_NO_EVEN_IF_THEY                                          = 10526,  -- No no no no no! Even if they use that half-rate spork, it'll take a tip-top summoner to defeat the prime avatar!
        LISTEN_UP_THE_FANDANGLED_WON_T_MAKE_IT                               = 10527,  -- Listen up. The fandangled % won't make it any easier for you to downright defeat the monster inside the crystal. Sure, it'll lower the power of the prime avatar to around #, but it will do the same to you! And on top of that, you'll only be able to summon that itty-bitty blue bugger, Carbuncle!
        AND_TO_MAKE_THINGS_WORSE_NOBODY_BUDDY_ELSE                           = 10528,  -- And to make things worse, nobody-buddy else can enter the crystal with you! You'll be battling one-on-one, man-to-man, Taru-et-Taru!
        YES_BUT_SIR_THE_RHINOSTERY_HAS_BEEN_PRESSING                         = 10529,  -- ... Yes, but sir... The Rhinostery has been pressing us to produce results. If we do not take some sort of action quickly...
