        IF_YOU_DO_NOT_BRING_THE_WE_GAVE                                      = 10545,  -- If you do not bring the % we gave you, my companion cannot warp you to [Ifrit's Cauldron/the Quicksand Caves/the Den of Rancor/Cape Teriggan/Fei'Yin/the Boyahda Tree].
        DID_YOU_REMEMBER_TO_BRING_THE                                        = 10546,  -- Did you remember to bring the %?
        WHAT_YOU_DEFEATED_THE_PRIME_AVATAR                                   = 10547,  -- What!? You defeated the prime avatar!?
        SIR                                                                  = 10548,  -- Sir!
        HMMM_JUST_AS_I_THOUGHTARU_THE_PRIME_AVATAR                           = 10549,  -- Hmmm... Just as I thoughtaru. The prime avatar that you fought with this spunky-junky tuning fork was nothing but a fake. Researching real avatars with real tuning forks is how real researchers do real research in the real world!
