        LET_ME_INTRODUCE_MYSELF_I_AM_FROM_THE_2                              = 10557,  -- Let me introduce myself. I am from the Rhinostery in Windurst. I do research on various living things.
        YOU_ALREADY_WEDDY_KNOW_ABOUT_THE_SUPER_GIANT                         = 10558,  -- You already-weddy know about the super-giant crystals, rightaru?
        THESE_CRYSTALS_ARE_FOUND_ALL_OVER_VANA_DIEL_2                        = 10559,  -- These crystals are found all over Vana'diel, and their energies affect the surrounding ecosystems. Our research team had been investigating the unusual emanations when POOF, out of nowhere, a prime avatar appeared and sliced 'n diced us down to size.
