        YOU_SHOULD_PROBABLY_START_OFF_BY_HEADING_TO                          = 10622,  -- You should probably start off by heading to Bastok and seeing if Kagetora in the Tenshodo has any leads.
        WHAT_YOU_FOUND_THIS_BY_FOLLOWING_ENSETSU_S                           = 10623,  -- What? You found this % by following Ensetsu's lead?
        THAT_WEASEL_IS_STILL_HIDING_SOMETHING_WE_RE                          = 10624,  -- That weasel is still hiding something. We're going to have to pay our little friend a visit...
        BUT_YOU_DON_T_HAVE_TO_WORRY_ABOUT                                    = 10625,  -- But you don't have to worry about that. Thanks again. Here is a little something for your trouble. Oh, and stay in touch. I may have some more work for you soon.
