        OBTAINED_KEY_ITEM_3                                                  = 11420,  -- Obtained key item: # %!
        YOUR_CURRENT_ALLOTMENT_OF_AFTER_CONSULTING_MY_RECORDS                = 11421,  -- Your current allotment of %? After consulting my records, I can confidently assert that you possess # [stone/stones].
        EXCHANGE_FOR_WHAT_CRUOR_NOTHING_RIGHT_NOW                            = 11422,  -- Exchange for what? (Cruor: #) Nothing right now. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #. %: #.
