        A_BEWITCHING_LIGHT_SHINES_FORTH_FROM_WITHIN_THE                      = 11435,  -- A bewitching light shines forth from within the crystallized walls of this fragment ripped from a Voidwalker, as if beckoning its bearer to come hither.
        A_TANTALIZING_LIGHT_SHINES_FORTH_FROM_WITHIN_THE                     = 11436,  -- A tantalizing light shines forth from within the crystallized walls of this fragment ripped from a Voidwalker, as if appealing to its bearer's most ardent desires.
        A_CRAZED_LIGHT_SHINES_FORTH_FROM_WITHIN_THE                          = 11437,  -- A crazed light shines forth from within the crystallized walls of this fragment ripped from a Voidwalker, as if seeking to breach the bearer's last bastion of sanity.
        THIS_WOULDN_T_HAPPEN_TO_BE_VOIDDUST_WOULD                            = 11438,  -- This wouldn't happen to be voiddust, would it? Very well then... Here is your voidstone. Please make good use of it.
        THIS_WOULDN_T_HAPPEN_TO_BE_VOIDDUST_WOULD_2                          = 11439,  -- This wouldn't happen to be voiddust, would it? Very well then... Here are your voidstones. Please make good use of them.
        IT_SEEMS_YOU_CANNOT_CARRY_ANY_MORE_VOIDSTONES                        = 11440,  -- It seems you cannot carry any more voidstones. Please return with voiddust in hand only after you've depleted your supply.
