        VOIDWATCH_DEBUG_MENU_EXIT_ALTER_PARTICIPATION_STATUS_ALTER           = 11444,  -- Voidwatch debug menu. Exit. Alter participation status. Alter jurisdiction. Alter stratum. Alter abyssite receipt level.
        PARTICIPATION_STATUS_ALTERED_TO                                      = 11445,  -- Participation status altered to [Eff, yeah/Heck, no].
