        LEVEL_CHANGED_TO                                                     = 11451,  -- Level changed to [1st time/2nd time and onwards/Abyssite evolution/2nd abyssite evolution and onwards].
        GREETINGS_AND_WELL_MET_I_AM_A_VOIDWATCH                              = 11452,  -- Greetings and well met. I am a Voidwatch scientist charged with researching the potential uses of atmacite.
        THOSE_WHO_POSSESS_MAY_COME_TO_ME_TO                                  = 11453,  -- Those who possess % may come to me to have their hard-won atmacite infused. Stratum abyssite also falls within my domain, so present to me any whose properties you wish to have analyzed.
        AH_I_M_ALSO_AUTHORIZED_TO_TELEPORT_FOLK                              = 11454,  -- Ah, I'm also authorized to teleport folk to operation sites. Quite versatile, aren't I?
        I_BEG_OF_YOU_FRIEND_LEND_US_YOUR                                     = 11455,  -- I beg of you, friend. Lend us your stout sword arm in the fight to protect Vana'diel from the Voidwalker threat.
        WHAT_WILL_YOU_DO_NOTHING_FOR_NOW_HAVE                                = 11456,  -- What will you do? Nothing for now. Have stratum abyssite examined. Request teleportation. Analyze atmacite. Ask about atmacite. Ask about atmacite enrichment.
        WHAT_WILL_YOU_DO_NOTHING_FOR_NOW_INFUSED                             = 11457,  -- What will you do? Nothing for now. Infused: % (lv.#) Infused: % (lv.#) Infused: % (lv.#) Purge atmacite. Infuse atmacite. Enrich atmacite.
        INFUSE_WHICH_ATMACITE_CRUOR_NONE_FOR_NOW_LV                          = 11458,  -- Infuse which atmacite? (Cruor: #) None for now. % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) Previous page. Next page.
        INFUSING_THE_LV_REQUIRES_CRUOR                                       = 11459,  -- Infusing the % (lv.#) requires # cruor.
