        YOU_DO_NOT_HAVE_ENOUGH_CRUOR_3                                       = 11461,  -- You do not have enough cruor.
        WHICH_ATMACITE_NONE_FOR_NOW_LV_LV_LV                                 = 11462,  -- [Infuse/Purge] which atmacite? None for now. % (lv.#) % (lv.#) % (lv.#)
        PURGE_LV_YES_NO                                                      = 11463,  -- Purge % (lv.#)? Yes. No.
        EXPENDS_CRUOR_AND_IS_NOW_INFUSED_WITH_LV                             = 11464,  -- % expends # cruor and is now infused with % (lv.#)!
        THE_ATMACITE_COULD_NOT_BE_INFUSED                                    = 11465,  -- The atmacite could not be infused...
        HAS_BEEN_PURGED_OF_THE_LV                                            = 11466,  -- % has been purged of the % (lv.#).
