        THE_HAS_BEEN_ENRICHED_TO_ITS_MAXIMUM_LEVEL                           = 11474,  -- The % has been enriched to its maximum level!
        THE_ATMACITE_S_ENRICHMENT_LEVEL_FAILED_TO_RISE                       = 11475,  -- The atmacite's enrichment level failed to rise...
