        I_SEE_THAT_S_HOW_IT_ALWAYS_IS                                        = 12245,  -- I see. That's how it always is. I should really be used to this treatment by now.
        SIGH_SOMETIMES_I_CAN_BARELY_WORK_UP_THE                              = 12246,  -- <Sigh> Sometimes I can barely work up the energy to do even the simplest task. Put your % here, I guess.
        OH_JOY_YOU_SUCCEEDED_IT_S_NOW_READY                                  = 12247,  -- Oh, joy...you succeeded. It's now ready to go whenever you are.
        I_VE_BEEN_TOLD_TO_MIND_THIS_WAYPOINT                                 = 12248,  -- I've been told to mind this waypoint, so use it as much as you want. No one ever takes my feelings into account anyway.
        AS_I_M_SURE_IS_OBVIOUS_MY_BURNING                                    = 12249,  -- As I'm sure is obvious, my burning passion for adventure led me to join this survey of the Middle Lands. On my way here, though, I <sigh> got lost in a cave. I always get lost.
        I_WAS_ABLE_TO_GET_OUT_BY_REMEMBERING                                 = 12250,  -- I was able to get out by remembering to put my right hand on the wall and...ugh, you don't care.
        EVENTUALLY_I_WANDERED_HERE_WITH_ALL_THE_STRANGE                      = 12251,  -- Eventually I wandered here. With all the strange artifacts around, this isn't the worst place I could've ended up.
        WHAT_ANASTASE_WANTS_A_REPORT_FROM_ME                                 = 12252,  -- What, Anastase wants a report from me?
        MUTTER_I_GUESS_I_DON_T_HAVE_A                                        = 12253,  -- <Mutter> I guess I don't have a choice... It'd look bad if you reported in and I didn't.
        THANKS_FOR_GIVING_ME_MORE_WORK_TO_DO                                 = 12254,  -- Thanks for giving me more work to do, stranger.
        OH_AND_WHILE_WE_RE_MAKING_UNNECESSARY_SMALL                          = 12255,  -- Oh, and while we're making unnecessary small talk...
        CAN_I_ASK_WHERE_IN_THE_WORLD_WE                                      = 12256,  -- Can I ask where in the world we are?
        NORG_THAT_S_NOT_WHERE_I_WANTED_TO                                    = 12257,  -- Norg...? That's not where I wanted to go at all...
        THAT_S_WHAT_HAPPENS_WHEN_ALL_YOU_RE                                  = 12258,  -- That's what happens when all you're told is to set a waypoint where the geomagnetic resonance is strong, though.
