        THANKS_FOR_THAT_IT_DOESN_T_HELP_MUCH                                 = 12260,  -- Thanks for that. It doesn't help much, but I'll take what I can get.
        HAVE_THIS_IN_RETURN_I_HATE_FISH_SO                                   = 12261,  -- Have this in return. I hate fish, so I wasn't going to eat it anyway.
